function stage_wise_budget_table_tdp_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('stage_wise_budget_table_tdp');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'project_id' => Request::lookup('project_id', ''),
		'project_title' => br2nl(Request::val('project_title', '')),
		'name_of_pi' => Request::val('name_of_pi', ''),
		'mobile_number' => Request::val('mobile_number', ''),
		'institute' => Request::val('institute', ''),
		'duration_in_months' => Request::val('duration_in_months', ''),
		'total_budget_specified' => Request::val('total_budget_specified', ''),
		'first_phase' => Request::val('first_phase', ''),
		'second_phase' => Request::val('second_phase', ''),
		'third_phase' => Request::val('third_phase', ''),
		'fourth_phase' => Request::val('fourth_phase', ''),
		'total' => Request::val('total', ''),
		'final_budget_to_be_allocated' => Request::val('final_budget_to_be_allocated', ''),
		'proposal_link' => Request::val('proposal_link', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('stage_wise_budget_table_tdp', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		stage_wise_budget_table_tdp_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function stage_wise_budget_table_tdp_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
