	if(!check_record_permission('stage_wise_budget_table_tdp', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: stage_wise_budget_table_tdp_before_delete
	if(function_exists('stage_wise_budget_table_tdp_before_delete')) {
		$args = [];
		if(!stage_wise_budget_table_tdp_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `stage_wise_budget_table_tdp` WHERE `id`='{$selected_id}'", $eo);

	// hook: stage_wise_budget_table_tdp_after_delete
	if(function_exists('stage_wise_budget_table_tdp_after_delete')) {
		$args = [];
		stage_wise_budget_table_tdp_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='stage_wise_budget_table_tdp' AND `pkValue`='{$selected_id}'", $eo);
}

function stage_wise_budget_table_tdp_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('stage_wise_budget_table_tdp', $selected_id, 'edit')) return false;

	$data = [
		'project_id' => Request::lookup('project_id', ''),
