		'duration_in_months' => Request::val('duration_in_months', ''),
		'total_budget_specified' => Request::val('total_budget_specified', ''),
		'first_phase' => Request::val('first_phase', ''),
		'second_phase' => Request::val('second_phase', ''),
		'third_phase' => Request::val('third_phase', ''),
		'fourth_phase' => Request::val('fourth_phase', ''),
		'total' => Request::val('total', ''),
		'final_budget_to_be_allocated' => Request::val('final_budget_to_be_allocated', ''),
		'proposal_link' => Request::val('proposal_link', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('stage_wise_budget_table_tdp', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: stage_wise_budget_table_tdp_before_update
	if(function_exists('stage_wise_budget_table_tdp_before_update')) {
		$args = ['old_data' => $old_data];
		if(!stage_wise_budget_table_tdp_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'stage_wise_budget_table_tdp',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="stage_wise_budget_table_tdp_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('stage_wise_budget_table_tdp', $data['selectedID'], calculated_fields()['stage_wise_budget_table_tdp']);

	// hook: stage_wise_budget_table_tdp_after_update
	if(function_exists('stage_wise_budget_table_tdp_after_update')) {
		if($row = getRecord('stage_wise_budget_table_tdp', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!stage_wise_budget_table_tdp_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('stage_wise_budget_table_tdp', $selected_id);
}

